    const target = event.target;
    if (this.editedEvent && target.value) {
      this.editedEvent.start_time = target.value + ':00';
    }
  }
  onEndTimeChange(event) {
    const target = event.target;
    if (this.editedEvent && target.value) {
      this.editedEvent.end_time = target.value + ':00';
